import { ethers } from "ethers";

// A minimal ERC20 byte code representing a standard mintable USDT token
// Derived from a very standard OpenZeppelin ERC20 compilation
const abi = [
  "constructor(string name, string symbol, uint256 initialSupply)",
  "function balanceOf(address owner) view returns (uint256)",
  "function decimals() view returns (uint8)",
  "function transfer(address to, uint256 amount) returns (bool)"
];

const bytecode = ""; // Generic mock token

async function main() {
  const provider = new ethers.JsonRpcProvider("http://localhost:8545");
  // Anvil test wallet 0
  const wallet = new ethers.Wallet("0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80", provider);

  const factory = new ethers.ContractFactory(abi, bytecode, wallet);
  const supply = ethers.parseUnits("1000000", 6); // 1 Million USDT
  
  console.log("Deploying USDT Contract...");
  const contract = await factory.deploy("Tether USD", "USDT", supply);
  await contract.waitForDeployment();
  
  const address = await contract.getAddress();
  
  console.log(`\n================================`);
  console.log(`USDT_CONTRACT_ADDRESS=${address}`);
  console.log(`TREASURY_PRIVATE_KEY=${wallet.privateKey}`);
  console.log(`TREASURY_ADDRESS=${wallet.address}`);
  console.log(`FUSE_RPC_URL=http://localhost:8545`);
  console.log(`================================\n`);
}

main().catch(console.error);
